Main.doTouch = function(myHandIdx,targetHandIdx) {
	if(Main.turnManager.gameOver) {
		return;
	}
	var actorIdx = Main.turnManager.currentPlayerIdx;
	var targetIdx = actorIdx == 0 ? 1 : 0;
	var actor = Main.turnManager.players[actorIdx];
	var target = Main.turnManager.players[targetIdx];
	var result = Main.engine.handleTouch(actor,myHandIdx,target,targetHandIdx);
	if(result.indexOf("错误") == 0) {
		window.alert(result);
	} else {
		Main.turnManager.checkGameOver();
		Main.render();
	}
};
Main.render = function() {
	var players = Main.turnManager.players;
	if(players.length < 2) {
		return;
	}
	var tmp = "第 " + Main.turnManager.turnCount;
	window.document.getElementById("turnIndicator").innerText = tmp + " 回合";
	var _g = 0;
	while(_g < 2) {
		var i = _g++;
		var p = players[i];
		window.document.getElementById("name" + i).innerText = p.name;
		window.document.getElementById("camp" + i).innerText = Std.string(p.camp);
		window.document.getElementById("hp" + i).innerText = Std.string(p.hp <= 0 ? 0 : p.hp);
		window.document.getElementById("h" + i + "_0").innerText = Std.string(p.hands[0]);
		window.document.getElementById("h" + i + "_1").innerText = Std.string(p.hands[1]);
		Main.toggleDeadClock("h" + i + "_0_box","dt" + i + "_0",p.hands[0] == 0,p.zeroTurns0);
		Main.toggleDeadClock("h" + i + "_1_box","dt" + i + "_1",p.hands[1] == 0,p.zeroTurns1);
		var card = window.document.getElementById("card" + i);
		if(card != null) {
			if(Main.turnManager.currentPlayerIdx == i && !Main.turnManager.gameOver) {
				card.className = "player-card active";
			} else {
				card.className = "player-card";
			}
		}
		var buffText = "";
		var _g1 = 0;
		var _g2 = p.buffList;
		while(_g1 < _g2.length) {
			var b = _g2[_g1];
			++_g1;
			buffText += "[" + b.name + " x" + b.layers + "] ";
		}
		window.document.getElementById("buffs" + i).innerText = buffText == "" ? "无" : buffText;
		var shieldsElement = window.document.getElementById("shields" + i);
		if(shieldsElement != null) {
			var shieldText = "";
			var _g3 = 0;
			var _g4 = p.shieldList;
			while(_g3 < _g4.length) {
				var s = _g4[_g3];
				++_g3;
				var typeName;
				switch(s.type._hx_index) {
				case 0:
					typeName = "物理护盾";
					break;
				case 1:
					typeName = "法术护盾";
					break;
				case 2:
					typeName = "物法护盾";
					break;
				case 3:
					typeName = "真实护盾";
					break;
				}
				shieldText += "[" + typeName + " " + s.amount + "/" + s.duration + "回合] ";
			}
			shieldsElement.innerText = shieldText == "" ? "无" : shieldText;
		}
		var customDisplay = window.document.getElementById("custom" + i);
		if(customDisplay != null) {
			var displayHtml = p.getCustomDisplay();
			if(displayHtml == "") {
				customDisplay.style.display = "none";
			} else {
				customDisplay.style.display = "block";
				customDisplay.innerHTML = displayHtml;
			}
		}
		var customActions = window.document.getElementById("actions" + i);
		if(customActions != null) {
			customActions.innerHTML = "";
			var isMyTurn = i == Main.turnManager.currentPlayerIdx;
			if(isMyTurn && !Main.turnManager.gameOver) {
				var actions = p.getCustomActions();
				var _g5 = 0;
				while(_g5 < actions.length) {
					var a = actions[_g5];
					++_g5;
					if(!a.enabled) {
						continue;
					}
					var btn = window.document.createElement("button");
					btn.textContent = a.label;
					btn.style.cssText = "margin:4px 4px 0 0;background:" + a.color + ";color:white;border:none;padding:6px 14px;border-radius:4px;cursor:pointer;font-size:13px;font-weight:bold;";
					var jsCode = StringTools.replace(a.onClickJS,"__IDX__",i == null ? "null" : "" + i);
					btn.setAttribute("data-action",jsCode);
					btn.onclick = function(e) {
						var code = e.currentTarget.getAttribute("data-action");
						eval(code);
					};
					customActions.appendChild(btn);
				}
			}
		}
	}
	if(Main.turnManager.gameOver) {
		window.document.getElementById("actionPanel").style.display = "none";
		var winMsg = Main.turnManager.winningCamp != null ? "🏆 最终胜出阵营：" + Std.string(Main.turnManager.winningCamp) : "💀 全场同归于尽，平局！";
		haxe_Log.trace("=========================================",{ fileName : "Main.hx", lineNumber : 493, className : "Main", methodName : "render"});
		haxe_Log.trace(winMsg,{ fileName : "Main.hx", lineNumber : 494, className : "Main", methodName : "render"});
		haxe_Log.trace("=========================================",{ fileName : "Main.hx", lineNumber : 495, className : "Main", methodName : "render"});
	}
};
Main.toggleDeadClock = function(boxId,textId,isZero,turns) {
	var box = window.document.getElementById(boxId);
	var txt = window.document.getElementById(textId);
	if(box != null && txt != null) {
		if(isZero && turns > 0) {
			box.className = "hand-box death-clock";
			txt.innerText = "0使用剩余次数: " + turns + "步";
		} else {
			box.className = "hand-box";
			txt.innerText = "";
		}
	}
};
